    }

    /* Validate individual label keys and values are not NULL */
    for (int i = 0; i < label_count; i++) {
        if (label_keys[i] == NULL || label_values[i] == NULL) {
            return -1;
        }
    }

    int offset = 0;
    int written;

    /* Write metric name */
    written = sprintf(metric_output + offset, "%s", metric_name);
    if (written < 0) {
        return -1;
    }
    offset += written;

    /* If no labels, just return the metric name */
    if (label_count == 0) {
        return offset;
    }

    /* Write opening brace */
    written = sprintf(metric_output + offset, "{");
    if (written < 0) {
        return -1;
    }
    offset += written;

    /* Write label key-value pairs */
    for (int i = 0; i < label_count; i++) {
        if (i > 0) {
            /* Write comma separator between labels */
            written = sprintf(metric_output + offset, ",");
            if (written < 0) {
                return -1;
            }
            offset += written;
        }

        /* Write key="value" */
        written = sprintf(metric_output + offset, "%s=\"%s\"", label_keys[i], label_values[i]);
        if (written < 0) {
            return -1;
        }
        offset += written;
    }

    /* Write closing brace */
    written = sprintf(metric_output + offset, "}");
    if (written < 0) {
        return -1;
    }
    offset += written;

    return offset;
}
